  constructor(message) {
    super(message); 
    this.code = 'BadRequest';
  }
}

export { BadRequestError };

const express = require('express');
const router = express.Router({ mergeParams: true });
const membersService = require('./service').service;

router.post('/', (req, res) => {
  if (!req.body.userId || !req.body.role) return sendError(res, 400, 'BadRequestError', 'UserId and role are required');
  const member = membersService.addMember(req.params.projectId, req.body);
  res.status(201).json({ member });
});

module.exports = { router };

const members = [];

export function addMember(projectId, { userId, role }) {
  if (!userId || !role) throw new BadRequestError('UserId and role are required');
  const member = { id: randomUUID(), projectId, userId, role };
  members.push(member);
  return member;
}

